def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 5:
            priority_score = 6000 + (ratio - 5) * 450 - np.log1p(ratio)
        elif 4 < ratio <= 5:
            priority_score = 3000 + (ratio - 4) * 350 + np.sqrt(ratio)
        elif 3 < ratio <= 4:
            priority_score = 1800 + (ratio - 3) * 250 + np.sin(ratio*3)
        elif 2 < ratio <= 3:
            priority_score = 1100 + (ratio - 2) * 210 + np.cos(ratio*2)
        elif 1 < ratio <= 2:
            priority_score = 800 + (ratio - 1) * 130 + np.tan((ratio - 1) * 0.3)
        elif ratio == 1:
            priority_score = 300 + np.exp(-abs(item - capacity))
        else:
            diff = capacity - item
            base = capacity if capacity != 0 else 1
            score = 0.0
            for j in range(1, 25):
                temp = (diff ** j) / (base ** j)
                if temp < 0.01:
                    score += temp * 200 / np.sqrt(j)
                elif 0.01 <= temp < 0.05:
                    score += temp * 50 / (j ** 1.1)
                elif 0.05 <= temp < 0.15:
                    score += temp * 25 / (j ** 1.7)
                else:
                    score += temp * 10 / (j ** 2.3)
            if score < 0.02:
                priority_score = score * 40 + np.exp(-item/capacity) * 1.5
            elif 0.02 <= score < 0.12:
                priority_score = 2 / (score + 0.25) + 8 * (item / capacity) - 0.5 * np.sin(item)
            else:
                adjustment = 0
                for k in range(1, 10):
                    adjustment += ((item / (capacity + k)) ** (k*0.7)) * (18 / (k + 3)) * np.cos(k)
                penalty = 0
                for m in range(1, 6):
                    penalty += ((capacity - item)**(m*1.2)) / ((item + 2)**(m+0.8)) * (10 / m) * np.sin(m*0.5)
                penalty = min(penalty, 8)
                priority_score = 2 / (score + 0.65) + adjustment - penalty
                if priority_score < 0:
                    priority_score = abs(priority_score) / 3 + 1
        if capacity - item < 0.15 * capacity:
            add_val = 0.3 * (capacity - item) ** 1.9 / max(1, capacity)
            if add_val > 0.1:
                priority_score += add_val * np.log1p(add_val * 10)
            else:
                priority_score += add_val * np.exp(-add_val)
        if item > 0.85 * capacity:
            priority_score *= 0.75 + 0.25 * np.sin(item / capacity * np.pi / 2)
        mod_index = i % 6
        if mod_index == 0:
            priority_score += 4 / (capacity + 4) + ((item + capacity) % (capacity + 3)) / (capacity + 10)
        elif mod_index == 1:
            priority_score -= 2 / (capacity + 5) + ((capacity - item) % 4) / (capacity + 9)
        elif mod_index == 2:
            priority_score += 0.8 * (np.sin(item / (capacity + 3)) + np.cos(capacity / (item + 3)))
        elif mod_index == 3:
            priority_score += np.log1p(abs(capacity - item) + 1) / (capacity + 6)
        elif mod_index == 4:
            temp_val = (item * capacity * 1.1) % (capacity + 4)
            priority_score += (temp_val / (capacity + 11)) ** 1.3
        else:
            priority_score += (np.tan(item / (capacity + 5)) + np.tanh(capacity / (item + 5))) * 0.5
        if i % 8 == 0 and priority_score > 150:
            priority_score /= 1.35
            for x in range(1, 5):
                increment = ((item / (capacity + x)) ** 2.2) * 6 / x + np.sin(x + ratio)
                priority_score += increment
        if item < 0.5 * capacity and ratio < 0.7:
            dec_factor = np.exp(-capacity / (item + 1)) * 0.4
            priority_score *= (1 - dec_factor)
            for y in range(2, 6):
                priority_score += ((capacity - item) / (capacity + y)) ** 1.4 / (y+1)
        priorities[i] = priority_score
    return priorities
